const __pageData = JSON.parse('{"title":"演进式架构：康威定律与逆康威","description":"深入探讨康威定律与逆康威策略的理论本质，系统阐述演进式架构的核心特征——增量变更、fitness functions与适当耦合，并映射到微前端、Monorepo治理、架构自动化验证和JS/TS生态的工程实践。","frontmatter":{"title":"演进式架构：康威定律与逆康威","description":"深入探讨康威定律与逆康威策略的理论本质，系统阐述演进式架构的核心特征——增量变更、fitness functions与适当耦合，并映射到微前端、Monorepo治理、架构自动化验证和JS/TS生态的工程实践。","date":"2026-05-01T00:00:00.000Z","tags":["应用设计","演进式架构","康威定律","微前端","Monorepo","架构治理"],"category":"theoretical-foundations"},"headers":[],"relativePath":"application-design/12-evolutionary-architecture.md","filePath":"application-design/12-evolutionary-architecture.md","lastUpdated":1777715369000}');
